import { useState } from "react";
import { Link, Navigate, useNavigate } from "react-router-dom";
import { isAutheticated, logout } from "../../utils/storage";
import "./Style.css"

const Header = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  }

  const navigate = useNavigate();
  return (
    <>
      &lt;&gt;
      <div classname="area-logo">
        {"{"}/* Container para o logo */{"}"}
        <a href="/">
          {"{"}/* Link para a página inicial */{"}"}
          <img
            src="/assets/img/logo.jpg"
            classname="area-logo-img"
            alt="Logo Patas do Amanhã"
          />
          {"{"}/* Imagem do logo com texto alternativo */{"}"}
        </a>
      </div>
      <nav classname="area-nav">
        {"{"}/* Navegação principal */{"}"}
        <ul classname="nav-list">
          {"{"}/* Lista de itens de navegação */{"}"}
          <li classname="nav-list-item">
            {"{"}/* Item de menu */{"}"}
            <a href="#">Início</a>
            {"{"}/* Link para página inicial */{"}"}
          </li>
          <li classname="nav-list-item has-submenu">
            {"{"}/* Item de menu com submenu */{"}"}
            <a href="#">
              Formas de ajudar
              <i classname="fa-solid fa-arrow-turn-down">
                {"{"}/* Ícone indicando submenu */{"}"}
              </i>
            </a>
            <i classname="fa-solid fa-arrow-turn-down">
              <ul classname="submenu" id="nossos-servicos">
                {"{"}/* Submenu dropdown */{"}"}
                <li>
                  <a href="/socio.html">Seja Sócio</a>
                </li>
                <li>
                  <a href="/SejaMelhorAmigo.html">Seja melhor amigo</a>
                </li>
                <li>
                  <a href="/empresas.html">Empresas</a>
                </li>
                <li>
                  <a href="/castracao.html">Castração</a>
                </li>
              </ul>
            </i>
          </li>
          <i classname="fa-solid fa-arrow-turn-down">
            <li classname="nav-list-item">
              <a href="/index.html">Adote</a>
            </li>
            <li classname="nav-list-item">
              <a href="/vakinha.html">Campanhas</a>
            </li>
            {"{"}/*{" "}
            <li className="nav-list-item">
              <a href="">Contato</a>
            </li>{" "}
            */{"}"}
          </i>
        </ul>
        <i classname="fa-solid fa-arrow-turn-down"></i>
      </nav>
      <i classname="fa-solid fa-arrow-turn-down">
        {"{"}/*{" "}
        <div className="pts-donate-btn">
          <a href="#final" className="pts-donate">
            Doação
          </a>
        </div>{" "}
        */{"}"}
        <div classname="nav-store-location">
          {"{"}/* Link para localização */{"}"}
          <a classname="store-location" href="./localizacao.html" target="_blank">
            <i classname="fa-solid fa-map-location-dot">
              {"{"}/* Ícone de localização */{"}"}
              <span>Nossa localização</span>
            </i>
          </a>
          <i classname="fa-solid fa-map-location-dot"></i>
        </div>
        <i classname="fa-solid fa-map-location-dot"></i>
      </i>
    </>

  )
}

export default Header;
